  { id: 52, img: "img/prod/xedap.png", name: "Xe đạp trẻ em cho bé gái bé trai", price: "2.500.000đ" },
]

const STORAGE_KEY = 'reward_selected_product_id'

const selectedRewardId = ref(
  localStorage.getItem(STORAGE_KEY)
    ? Number(localStorage.getItem(STORAGE_KEY))
    : null
)

const selectedProduct = ref(null)

/* tách riêng 2 popup */
const showRewardPopup = ref(false)
const showMarketingPopup = ref(false)

const hasSelectedAny = computed(() => selectedRewardId.value !== null)

function isSelected(product) {
  return selectedRewardId.value === product.id
}

function isOtherProduct(product) {
  return hasSelectedAny.value && !isSelected(product)
}

function showRewardById(productId) {
  const product = products.find(item => item.id === productId)
  if (!product) return

  if (hasSelectedAny.value) {
    if (selectedRewardId.value === productId) {
      selectedProduct.value = product
      showRewardPopup.value = true
    }
    return
  }

  selectedRewardId.value = productId
  selectedProduct.value = product
  showRewardPopup.value = true

  localStorage.setItem(STORAGE_KEY, String(productId))
}

function closeRewardPopup() {
  showRewardPopup.value = false
}

/* ========= SLIDE TRÊN ========= */
const topSlides = [
  '/img/slide04.png',
  '/img/slide03.png',
  '/img/qttamp100.png',
]

const currentTop = ref(0)
let autoTop = null

const styleTop = computed(() => ({
  transform: `translateX(-${currentTop.value * 100}%)`,
  transition: '0.5s ease',
}))

function nextTop() {
  currentTop.value = (currentTop.value + 1) % topSlides.length
}

function goTop(index) {
  currentTop.value = index
}

function startTop() {
  stopTop()
  autoTop = setInterval(nextTop, 3000)
}

function stopTop() {
  if (autoTop) clearInterval(autoTop)
}

/* ========= SLIDE DƯỚI ========= */
const footerSlides = [
  '/img/slide03.png',
  '/img/qttamp100.png',
]

const currentFooter = ref(0)
let autoFooter = null

const styleFooter = computed(() => ({
  transform: `translateX(-${currentFooter.value * 100}%)`,
  transition: '0.5s ease',
}))

function nextFooter() {
  currentFooter.value = (currentFooter.value + 1) % footerSlides.length
}

function goFooter(index) {
  currentFooter.value = index
}

function startFooter() {
  stopFooter()
  autoFooter = setInterval(nextFooter, 3000)
}

function stopFooter() {
  if (autoFooter) clearInterval(autoFooter)
}

onMounted(() => {
  startTop()
  startFooter()

  setTimeout(() => {
    showMarketingPopup.value = true
    document.body.style.overflow = 'hidden'
  }, 100)
})

onBeforeUnmount(() => {
  stopTop()
  stopFooter()
})
</script>

